"use client";

import { useEffect, useState } from "react";
import { getPharmacyList } from "@/util/nightApi"; // 위에서 만든 API 함수
import "./pharmacy.css";

// 백엔드 DTO와 맞춘 인터페이스
interface Pharmacy {
  name: string;
  address: string;
  tel: string;
  lat: number;
  lon: number;
  endTime: string;
}

export default function PharmacyPage() {
  const [loading, setLoading] = useState(false);
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [location, setLocation] = useState<{ lat: number; lon: number } | null>(null);
  const [errorMsg, setErrorMsg] = useState("");

  // 1. 현재 위치 가져오기
  const getMyLocation = () => {
    setLoading(true);
    setErrorMsg("");
    setPharmacies([]); // 기존 리스트 초기화

    if (!navigator.geolocation) {
      setErrorMsg("위치 기능을 사용할 수 없습니다.");
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        setLocation({ lat: latitude, lon: longitude });
        fetchPharmacies(latitude, longitude); // 위치 얻으면 바로 조회
      },
      (err) => {
        setErrorMsg("위치 권한을 허용해주세요.");
        setLoading(false);
      }
    );
  };

  // 2. 백엔드 API 호출
  const fetchPharmacies = async (lat: number, lon: number) => {
    try {
      const data = await getPharmacyList(lat, lon);
      setPharmacies(data);
      if (data.length === 0) {
        setErrorMsg(""); // 에러는 아니지만 데이터 없음
      }
    } catch (e) {
      setErrorMsg("약국 정보를 불러오는데 실패했습니다.");
    } finally {
      setLoading(false);
    }
  };

  // 페이지 접속 시 자동 실행
  useEffect(() => {
    getMyLocation();
  }, []);

  return (
    <div className="pharmacy-container">
      <div className="pharmacy-header">
        <h1 className="pharmacy-title">심야 약국 찾기 🌙</h1>
        <p className="pharmacy-desc">
          내 주변에서 <strong>저녁 7시 이후</strong>까지 여는 약국을 찾아줍니다.
        </p>
      </div>

      <div className="control-panel">
        <div className="status-text">
          {loading ? "위치 확인 및 조회 중..." : 
           errorMsg ? <span style={{color:'#ef4444'}}>{errorMsg}</span> : 
           location ? "현재 위치 기준 조회 완료" : "위치 권한 확인 필요"}
        </div>
        <button 
          className="btn-refresh" 
          onClick={getMyLocation} 
          disabled={loading}
        >
          {loading ? "검색 중..." : "새로고침"}
        </button>
      </div>

      <div className="pharmacy-list">
        {pharmacies.length > 0 ? (
          pharmacies.map((ph, index) => (
            <div key={index} className="pharmacy-card">
              <div className="ph-info">
                <span className="ph-name">{ph.name}</span>
                <div className="ph-addr">{ph.address}</div>
                <div style={{display:'flex', gap:'10px', alignItems:'center', marginTop:'8px'}}>
                  <span className="ph-time-badge">
                    오늘 마감: {ph.endTime}
                  </span>
                  <a href={`tel:${ph.tel}`} style={{textDecoration:'none', color:'#666', fontSize:'13px', display:'flex', alignItems:'center', gap:'4px'}}>
                    📞 {ph.tel}
                  </a>
                </div>
              </div>
              <div className="ph-distance">
                <a 
                  href={`https://map.kakao.com/link/to/${ph.name},${ph.lat},${ph.lon}`} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  style={{
                    backgroundColor: '#10b981', 
                    color: 'white', 
                    padding: '8px 12px', 
                    borderRadius: '6px', 
                    textDecoration: 'none',
                    fontSize: '13px'
                  }}
                >
                  길찾기
                </a>
              </div>
            </div>
          ))
        ) : (
          !loading && !errorMsg && (
            <div className="empty-msg">
              주변 2km 내에 19시 이후 운영하는 약국이 없습니다. 😭<br />
              (조금 더 번화가로 이동해서 다시 검색해보세요)
            </div>
          )
        )}
      </div>
    </div>
  );
}